1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  cursed?: boolean;
8	  enchantment?: number;
9	  material?: string;
10	}
11	
12	export interface Damage {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	export interface Incident {
18	  cause: string;
19	  damages: Damage[];
20	}
21	
22	export interface Policy {
23	  items: Item[];
24	  insuranceSum: number;
25	  cap: number;
26	  remainingCap: number;
27	}
28	
29	const PROCESSING_FEE = 5;
30	const FIRST_INSURANCE_RATE = 0.1;
31	
32	const BASE_PREMIUM: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const INSURANCE_VALUE: Record<string, number> = {
42	  sword: 1000,
43	  amulet: 600,
44	  staff: 800,
45	  potion: 400,
46	  rune: 250,
47	  moonstone: 250,
48	};
49	
50	const CAP_MULTIPLIER = 2;
51	
52	export const createPolicy = (items: Item[]): Policy => {
53	  const insuranceSum = sum(items.map((item) => INSURANCE_VALUE[item.type]));
54	  const cap = insuranceSum * CAP_MULTIPLIER;
55	  return { items, insuranceSum, cap, remainingCap: cap };
56	};
57	
58	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
59	const BLOCK_BASE = 60;
60	
61	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUM;
62	
63	const assertKnownItemTypes = (items: Item[]): void => {
64	  for (const item of items) {
65	    if (!isKnownItemType(item.type)) {
66	      throw new Error(`Unknown item type: ${item.type}`);
67	    }
68	  }
69	};
70	
71	const baseForGroup = (type: string, count: number): number => {
72	  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
73	  return BASE_PREMIUM[type] * count;
74	};
75	
76	const countBy = <T>(items: readonly T[], keyOf: (item: T) => string): Map<string, number> => {
77	  const counts = new Map<string, number>();
78	  for (const item of items) {
79	    const key = keyOf(item);
80	    counts.set(key, (counts.get(key) ?? 0) + 1);
81	  }
82	  return counts;
83	};
84	
85	const countByType = (items: Item[]): Map<string, number> =>
86	  countBy(items, (item) => item.type);
87	
88	const sum = (numbers: number[]): number =>
89	  numbers.reduce((total, n) => total + n, 0);
90	
91	const groupBaseTotal = (items: Item[]): number => {
92	  const counts = countByType(items);
93	  return sum(
94	    Array.from(counts, ([type, count]) => baseForGroup(type, count)),
95	  );
96	};
97	
98	const itemSurchargeTotal = (items: Item[]): number =>
99	  sum(items.map((item) => surchargesFor(item)));
100	
101	const surchargesFor = (item: Item): number => {
102	  const base = BASE_PREMIUM[item.type];
103	  let total = 0;
104	  if (item.cursed) total += base * 0.5;
105	  if ((item.enchantment ?? 0) >= 5) total += base * 0.3;
106	  return total;
107	};
108	
109	const LOYALTY_THRESHOLD_YEARS = 2;
110	const LOYALTY_DISCOUNT_RATE = 0.2;
111	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
112	
113	export const quote = (
114	  customer: Customer,
115	  items: Item[],
116	  priorContracts: number,
117	): number => {
118	  assertKnownItemTypes(items);
119	  const groupBase = groupBaseTotal(items);
120	  const firstInsurance = groupBase * FIRST_INSURANCE_RATE;
121	  const surcharges = itemSurchargeTotal(items);
122	  const loyaltyDiscount =
123	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? groupBase * LOYALTY_DISCOUNT_RATE : 0;
124	  const followUpDiscount = priorContracts > 0 ? groupBase * FOLLOW_UP_DISCOUNT_RATE : 0;
125	  return Math.ceil(
126	    groupBase + firstInsurance + surcharges - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
127	  );
128	};
129	
130	const DEDUCTIBLE = 100;
131	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
132	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
133	
134	const isHighlyEnchanted = (item: Item | undefined): boolean =>
135	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
136	
137	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
138	  isHighlyEnchanted(item)
139	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
140	    : damage.amount;
141	
142	const findInsuredItem = (policy: Policy, itemType: string): Item | undefined =>
143	  policy.items.find((item) => item.type === itemType);
144	
145	const payoutForDamage = (damage: Damage, policy: Policy): number => {
146	  const item = findInsuredItem(policy, damage.itemType);
147	  return reimbursableAmount(damage, item) - DEDUCTIBLE;
148	};
149	
150	const assertDamagesCovered = (policy: Policy, damages: Damage[]): void => {
151	  const itemCounts = countByType(policy.items);
152	  const damageCounts = countBy(damages, (damage) => damage.itemType);
153	  for (const [type, count] of damageCounts) {
154	    if (count > (itemCounts.get(type) ?? 0)) {
155	      throw new Error(`Damage count for ${type} exceeds policy coverage`);
156	    }
157	  }
158	};
159	
160	export const claim = (
161	  policy: Policy,
162	  incident: Incident,
163	): { payout: number; remainingCap: number } => {
164	  assertDamagesCovered(policy, incident.damages);
165	  const payout = sum(incident.damages.map((damage) => payoutForDamage(damage, policy)));
166	  return { payout, remainingCap: policy.remainingCap - payout };
167	};
